from dataclasses import dataclass, field

@dataclass
class TrialResult:
    trajectory: list[dict]  # list of {role, content} turns
    reward: float           # 0.0 – 1.0; 1.0 = solved
    steps: int

@dataclass
class ReflexionState:
    task: str
    lessons: list[str] = field(default_factory=list)   # verbal lessons
    trials: list[TrialResult] = field(default_factory=list)
    solved: bool = False

    def best_trial(self) -> TrialResult | None:
        return max(self.trials, key=lambda t: t.reward) if self.trials else None

    def memory_prefix(self, max_tokens: int = 800) -> str:
        """Return lessons formatted as a context prefix, newest first, token-capped."""
        if not self.lessons:
            return ""
        lines = []
        total = 0
        for lesson in reversed(self.lessons):
            tokens_approx = len(lesson.split())
            if total + tokens_approx > max_tokens:
                break
            lines.insert(0, f"- {lesson}")
            total += tokens_approx
        return "Lessons from prior attempts:\n" + "\n".join(lines) + "\n\n"

class EpisodicMemory:
    def __init__(self, max_lessons: int = 6, max_tokens_per_lesson: int = 150):
        self.lessons: list[str] = []
        self.max_lessons = max_lessons
        self.max_tokens_per_lesson = max_tokens_per_lesson

    def add(self, lesson: str) -> None:
        # Truncate to token budget
        words = lesson.split()
        if len(words) > self.max_tokens_per_lesson:
            lesson = " ".join(words[:self.max_tokens_per_lesson]) + "..."
        self.lessons.append(lesson)
        # Sliding window: drop oldest
        if len(self.lessons) > self.max_lessons:
            self.lessons.pop(0)

    def context_prefix(self) -> str:
        if not self.lessons:
            return ""
        items = "\n".join(f"{i+1}. {l}" for i, l in enumerate(self.lessons))
        return f"Important lessons from your previous attempts:\n{items}\n\n"

    def is_novel(self, candidate: str, similarity_threshold: float = 0.85) -> bool:
        """Simple token-overlap novelty check (replace with embedding similarity in prod)."""
        candidate_tokens = set(candidate.lower().split())
        for existing in self.lessons:
            existing_tokens = set(existing.lower().split())
            if not candidate_tokens or not existing_tokens:
                continue
            overlap = len(candidate_tokens & existing_tokens)
            jaccard = overlap / len(candidate_tokens | existing_tokens)
            if jaccard > similarity_threshold:
                return False
        return True

import pytest

# --- Evaluator tests ---
def test_exact_match_pass():
    task = "What is 2 + 2? Expected answer: 4"
    traj = [{"role": "assistant", "content": "Answer: 4"}]
    assert exact_match_evaluator(task, traj) == 1.0

def test_exact_match_fail():
    task = "What is 2 + 2? Expected answer: 4"
    traj = [{"role": "assistant", "content": "Answer: 5"}]
    assert exact_match_evaluator(task, traj) == 0.0

# --- Memory tests ---
def test_sliding_window_evicts_oldest():
    mem = EpisodicMemory(max_lessons=3)
    for i in range(4):
        mem.add(f"Lesson {i}")
    assert "Lesson 0" not in mem.lessons
    assert len(mem.lessons) == 3

def test_context_prefix_empty():
    mem = EpisodicMemory()
    assert mem.context_prefix() == ""

def test_novelty_check():
    mem = EpisodicMemory()
    mem.add("Always verify the output format before returning the answer.")
    # Near-duplicate should not be novel
    assert not mem.is_novel("Always check the output format before returning.", threshold=0.5)
    # Unrelated lesson is novel
    assert mem.is_novel("Use binary search to improve time complexity.")

# --- Loop integration test with stub evaluator ---
def test_reflexion_loop_exits_on_success():
    rewards = iter([0.0, 0.0, 1.0])  # fails twice, succeeds on trial 3
    call_count = {"n": 0}

    def stub_evaluator(task, traj):
        call_count["n"] += 1
        return next(rewards)

    state = ReflexionGraphState(
        task="test", lessons=[], last_trajectory=[],
        last_reward=0.0, trial_count=0, solved=False,
    )
    # Simulate the loop manually
    for _ in range(5):
        if state["solved"] or state["trial_count"] >= 5:
            break
        state = {**state, "last_trajectory": [{"role": "assistant", "content": "ans"}],
                 "trial_count": state["trial_count"] + 1}
        reward = stub_evaluator(state["task"], state["last_trajectory"])
        state = {**state, "last_reward": reward, "solved": reward >= 1.0}

    assert state["trial_count"] == 3
    assert state["solved"] is True
